import android.content.Intent;
import android.content.pm.PackageManager;
import android.content.pm.ResolveInfo;
import java.util.HashSet;
import java.util.Iterator;
import java.security.MessageDigest;
import java.io.File;
import java.io.BufferedReader;
import java.io.FileReader;
import com.joaomgcd.taskerm.action.java.JavaCodeException;

String taskId = tasker.getVariable("task_id");
if (taskId == null) {
    throw new JavaCodeException("The Tasker variable %task_id is not set.");
}

String appsPath = tasker.getVariable("apps_path");
if (appsPath == null) {
    throw new JavaCodeException("The Tasker variable %apps_path is not set. Please define the file path for the cache.");
}

String previousHash = tasker.getVariable("pkgs_hash");
if (previousHash == null) {
    previousHash = "";
}

pm = context.getPackageManager();

intent = new Intent(Intent.ACTION_MAIN);
intent.addCategory(Intent.CATEGORY_LAUNCHER);

activities = pm.queryIntentActivities(intent, 0);

uniquePackages = new HashSet();

for (int i = 0; i < activities.size(); i++) {
    ResolveInfo info = (ResolveInfo) activities.get(i);
    uniquePackages.add(info.activityInfo.packageName);
}

StringBuilder packagesBuilder = new StringBuilder();
packagesBuilder.append("[");

Iterator iterator = uniquePackages.iterator();
while (iterator.hasNext()) {
    packagesBuilder.append("\"" + iterator.next() + "\"");
    if (iterator.hasNext()) {
        packagesBuilder.append(", ");
    }
}

packagesBuilder.append("]");

String packagesJson = packagesBuilder.toString();

MessageDigest digest = MessageDigest.getInstance("SHA-1");
byte[] hashBytes = digest.digest(packagesJson.getBytes("UTF-8"));

StringBuilder sha1Builder = new StringBuilder();
for (byte b : hashBytes) {
    sha1Builder.append(String.format("%02x", b));
}

String currentHash = sha1Builder.toString();

File cacheFile = new File(appsPath);
boolean cacheExists = cacheFile.exists();

boolean cacheEmpty = false;
if (cacheExists) {
    try {
        BufferedReader reader = new BufferedReader(new FileReader(cacheFile));
        StringBuilder fileContent = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            fileContent.append(line.trim());
        }
        reader.close();
        String content = fileContent.toString().trim();
        cacheEmpty = content.isEmpty() || content.equals("[]");
    } catch (Exception e) {
        cacheEmpty = true;
    }
}

boolean hashChanged = !currentHash.equals(previousHash);
boolean hasChanged = !cacheExists || cacheEmpty || hashChanged;

String payload;
if (hasChanged) {
    tasker.setVariable("pkgs_hash", currentHash);
    payload = "{\"changed\": true, \"packages\": " + packagesJson + "}";
} else {
    payload = "{\"changed\": false}";
}

return "{\"id\": " + taskId + ", \"status\": \"success\", \"payload\": " + payload + "}";

