import android.os.Environment;
import java.io.File;

base = Environment.getExternalStorageDirectory().getAbsolutePath();

screenshotCandidates = new String[]{
    base + "/DCIM/Screenshots",
    base + "/Pictures/Screenshots",
    base + "/Pictures/ScreenShots",
    base + "/MIUI/Gallery/Pictures/Screenshots",
    base + "/Screenshots",
};
screenshotPath = base + "/DCIM/Screenshots";
for (int i = 0; i < screenshotCandidates.length; i++) {
    dir = new File(screenshotCandidates[i]);
    if (dir.exists() && dir.isDirectory()) { screenshotPath = screenshotCandidates[i]; break; }
}

recordingCandidates = new String[]{
    base + "/DCIM/ScreenRecorder",
    base + "/DCIM/ScreenRecordings",
    base + "/DCIM/Screen recordings",
    base + "/Movies/ScreenRecorder",
    base + "/Movies/ScreenRecordings",
    base + "/Movies/Screen recordings",
    base + "/Movies",
    base + "/Videos/ScreenRecordings",
    base + "/MIUI/Gallery/Videos/ScreenRecordings",
    base + "/ScreenRecordings",
};
screenRecordingPath = base + "/DCIM/ScreenRecorder";
for (int i = 0; i < recordingCandidates.length; i++) {
    dir = new File(recordingCandidates[i]);
    if (dir.exists() && dir.isDirectory()) { screenRecordingPath = recordingCandidates[i]; break; }
}

tasker.setVariable("screenshots_path", screenshotPath);
tasker.setVariable("recordings_path", screenRecordingPath);

import java.io.File;
import java.io.FileInputStream;
import java.io.InputStreamReader;
import java.io.BufferedReader;
import com.joaomgcd.taskerm.action.java.JavaCodeException;

baseDir = tasker.getVariable("tg_work_dir");

if (baseDir == null || baseDir == void) {
    tasker.showToast("Variable %tg_work_dir is not set. Please set it before running this script.");
    throw new JavaCodeException("Variable %tg_work_dir is not set. Please set it before running this script.");
}

dataDir = baseDir + "/src/data/";
i18nDir = baseDir + "/src/i18n/";

fileNames = new String[]{"apps.json", "activities.json", "stats.json", "folders.json", "settings.json"};

String readFile(dir, fileName) {
    file = new File(dir, fileName);
    if (!file.exists() || !file.isFile()) return null;

    fis = null;
    isr = null;
    br = null;

    try {
        fis = new FileInputStream(file);
        isr = new InputStreamReader(fis, "UTF-8");
        br = new BufferedReader(isr);
        sb = new StringBuffer();

        line = br.readLine();
        while (line != null) {
            sb.append(line).append("\n");
            line = br.readLine();
        }

        return sb.toString();
    } catch (Exception e) {
        tasker.log("Error reading file " + fileName + ": " + e.getMessage());
        return null;
    } finally {
        try { if (br != null) br.close(); } catch (Exception e) {}
        try { if (isr != null) isr.close(); } catch (Exception e) {}
        try { if (fis != null) fis.close(); } catch (Exception e) {}
    }
}

settingsContent = null;

for (i = 0; i < fileNames.length; i++) {
    fileName = fileNames[i];
    varName = fileName.replace(".json", "");
    content = readFile(dataDir, fileName);

    if (fileName.equals("settings.json")) settingsContent = content;

    tasker.setVariable(varName, content, content != null);
}

systemLanguage = tasker.getVariable("system_language");
langCode = null;

if (settingsContent != null) {
    langKey = tasker.getVariable("settings.language");
    langCode = (langKey != null && !langKey.equals("null")) ? langKey : (systemLanguage != null ? systemLanguage : "en");
} else {
    langCode = (systemLanguage != null ? systemLanguage : "en");
}

if (langCode != null) {
    translationsContent = readFile(i18nDir, langCode + ".json");
    tasker.setVariable("translations", translationsContent, translationsContent != null);
}
